import os

RES_LAYOUT = os.path.join("Sujood", "app", "src", "main", "res", "layout")

overlay_xml = '<?xml version="1.0" encoding="utf-8"?>\n<androidx.constraintlayout.widget.ConstraintLayout\n    xmlns:android="http://schemas.android.com/apk/res/android"\n    xmlns:app="http://schemas.android.com/apk/res-auto"\n    android:layout_width="match_parent"\n    android:layout_height="match_parent"\n    android:background="@drawable/overlay_background">\n\n    <!-- SPIRITUAL FOCUS label top-left -->\n    <TextView\n        android:id="@+id/spiritualFocusLabel"\n        android:layout_width="wrap_content"\n        android:layout_height="wrap_content"\n        android:text="SPIRITUAL FOCUS"\n        android:textColor="#99A3B8CC"\n        android:textSize="10sp"\n        android:letterSpacing="0.15"\n        android:fontFamily="sans-serif-medium"\n        android:layout_marginStart="24dp"\n        android:layout_marginTop="56dp"\n        app:layout_constraintTop_toTopOf="parent"\n        app:layout_constraintStart_toStartOf="parent"/>\n\n    <!-- Progress percentage top-right -->\n    <TextView\n        android:id="@+id/progressPercent"\n        android:layout_width="wrap_content"\n        android:layout_height="wrap_content"\n        android:text="0%"\n        android:textColor="#FF1132D4"\n        android:textSize="12sp"\n        android:fontFamily="sans-serif-bold"\n        android:layout_marginEnd="24dp"\n        android:layout_marginTop="56dp"\n        app:layout_constraintTop_toTopOf="parent"\n        app:layout_constraintEnd_toEndOf="parent"/>\n\n    <!-- Progress bar -->\n    <ProgressBar\n        android:id="@+id/focusProgressBar"\n        style="?android:attr/progressBarStyleHorizontal"\n        android:layout_width="0dp"\n        android:layout_height="4dp"\n        android:layout_marginStart="24dp"\n        android:layout_marginEnd="24dp"\n        android:layout_marginTop="8dp"\n        android:progressDrawable="@drawable/progress_bar_drawable"\n        android:progress="0"\n        android:max="100"\n        app:layout_constraintTop_toBottomOf="@id/spiritualFocusLabel"\n        app:layout_constraintStart_toStartOf="parent"\n        app:layout_constraintEnd_toEndOf="parent"/>\n\n    <!-- Custom circular arc timer view -->\n    <com.sujood.app.ui.views.CircularTimerView\n        android:id="@+id/circularTimer"\n        android:layout_width="260dp"\n        android:layout_height="260dp"\n        android:layout_marginTop="48dp"\n        app:layout_constraintTop_toBottomOf="@id/focusProgressBar"\n        app:layout_constraintStart_toStartOf="parent"\n        app:layout_constraintEnd_toEndOf="parent"/>\n\n    <!-- MM:SS countdown inside the arc -->\n    <TextView\n        android:id="@+id/timerText"\n        android:layout_width="wrap_content"\n        android:layout_height="wrap_content"\n        android:text="05:00"\n        android:textColor="#FFFFFFFF"\n        android:textSize="60sp"\n        android:fontFamily="sans-serif-light"\n        android:letterSpacing="-0.03"\n        app:layout_constraintTop_toTopOf="@id/circularTimer"\n        app:layout_constraintBottom_toBottomOf="@id/circularTimer"\n        app:layout_constraintStart_toStartOf="@id/circularTimer"\n        app:layout_constraintEnd_toEndOf="@id/circularTimer"\n        app:layout_constraintVertical_bias="0.42"/>\n\n    <!-- REMAINING label -->\n    <TextView\n        android:id="@+id/remainingLabel"\n        android:layout_width="wrap_content"\n        android:layout_height="wrap_content"\n        android:text="REMAINING"\n        android:textColor="#668892A4"\n        android:textSize="11sp"\n        android:letterSpacing="0.15"\n        android:fontFamily="sans-serif-medium"\n        android:layout_marginTop="4dp"\n        app:layout_constraintTop_toBottomOf="@id/timerText"\n        app:layout_constraintStart_toStartOf="@id/circularTimer"\n        app:layout_constraintEnd_toEndOf="@id/circularTimer"/>\n\n    <!-- Quote marks -->\n    <TextView\n        android:id="@+id/quoteMarks"\n        android:layout_width="wrap_content"\n        android:layout_height="wrap_content"\n        android:text="\\u201C\\u201C"\n        android:textColor="#331132D4"\n        android:textSize="48sp"\n        android:layout_marginTop="40dp"\n        app:layout_constraintTop_toBottomOf="@id/circularTimer"\n        app:layout_constraintStart_toStartOf="parent"\n        app:layout_constraintEnd_toEndOf="parent"/>\n\n    <!-- Quote text (set dynamically from settings) -->\n    <TextView\n        android:id="@+id/quoteText"\n        android:layout_width="0dp"\n        android:layout_height="wrap_content"\n        android:text="\\u201cSuccess is found in the prayer.\\u201d"\n        android:textColor="#E6FFFFFF"\n        android:textSize="22sp"\n        android:fontFamily="sans-serif-light"\n        android:fontStyle="italic"\n        android:textAlignment="center"\n        android:gravity="center"\n        android:layout_marginStart="32dp"\n        android:layout_marginEnd="32dp"\n        android:layout_marginTop="4dp"\n        app:layout_constraintTop_toBottomOf="@id/quoteMarks"\n        app:layout_constraintStart_toStartOf="parent"\n        app:layout_constraintEnd_toEndOf="parent"/>\n\n    <!-- Thin divider line -->\n    <View\n        android:id="@+id/divider"\n        android:layout_width="48dp"\n        android:layout_height="1dp"\n        android:background="#33FFFFFF"\n        android:layout_marginTop="28dp"\n        app:layout_constraintTop_toBottomOf="@id/quoteText"\n        app:layout_constraintStart_toStartOf="parent"\n        app:layout_constraintEnd_toEndOf="parent"/>\n\n    <!-- Emergency call button (always accessible, even during lock) -->\n    <Button\n        android:id="@+id/emergencyPhoneButton"\n        android:layout_width="wrap_content"\n        android:layout_height="40dp"\n        android:text="Emergency Call"\n        android:textColor="#88FFFFFF"\n        android:textSize="12sp"\n        android:background="@null"\n        android:layout_marginBottom="4dp"\n        app:layout_constraintBottom_toTopOf="@id/iPrayedButton"\n        app:layout_constraintStart_toStartOf="parent"\n        app:layout_constraintEnd_toEndOf="parent"/>\n\n    <!-- I\'ve Prayed button -->\n    <Button\n        android:id="@+id/iPrayedButton"\n        android:layout_width="0dp"\n        android:layout_height="56dp"\n        android:text="I\\u2019ve Prayed \\u2713"\n        android:textColor="#FFFFFFFF"\n        android:textSize="16sp"\n        android:fontFamily="sans-serif-medium"\n        android:background="@drawable/prayed_button_bg"\n        android:layout_marginStart="24dp"\n        android:layout_marginEnd="24dp"\n        android:layout_marginBottom="32dp"\n        app:layout_constraintBottom_toBottomOf="parent"\n        app:layout_constraintStart_toStartOf="parent"\n        app:layout_constraintEnd_toEndOf="parent"/>\n\n</androidx.constraintlayout.widget.ConstraintLayout>\n'

path = os.path.join(RES_LAYOUT, "prayer_lock_overlay.xml")
with open(path, "w", encoding="utf-8", newline="\n") as f:
    f.write(overlay_xml)
print("  \u2713 prayer_lock_overlay.xml")

print("\nDone! Run:")
print("  git add .")
print("  git commit -m \"fix: rewrite overlay XML cleanly\"")
print("  git push")
print("  cd Sujood && ./gradlew assembleDebug")
